sql:
SELECT campsite_name || ' has an average rating of ' || CAST(AVG(rating) AS TEXT) AS campsite_average_rating
FROM campsites
GROUP BY campsite_id;

external_knowledge:
- 'surpasses the stars' refers to a rating greater than 3;
- 'abundance of amenities that exceed the count of two' refers to more than 2 amenities;
- 'stands out' means it is the top result when ordered by average rating.

- "Crown jewel" refers to the region with the highest total revenue and average rating;
- "Vast forest of camping destinations" is a metaphor for the collection of regions and campsites;
- "Generating the most revenue" indicates the highest total revenue from bookings;
- "Boasting the highest average rating" indicates the highest average rating among regions with the same revenue.

sql:
SELECT campsite_id 
FROM campsites 
WHERE rating = (SELECT MAX(rating) FROM campsites);

SELECT campsite_name, AVG(rating) AS average_rating
FROM campsites
GROUP BY campsite_name;

SELECT campsite_name, rating
FROM campsites
WHERE rating = (SELECT MIN(rating) FROM campsites);

external_knowledge:
- 'Top-rated campsites' refers to campsites with the highest rating in each country;
- 'Average rating' is the mean rating of all campsites in a country;
- 'More than 10 campsites' means the country has at least 11 campsites.

- "shine brightly" refers to high average ratings;
- "popularity" is measured by the total number of bookings;
- "top 10" means the campsites are ranked within the top 10 positions for both metrics.

- 'stars that shine over the region' refers to the average rating of campsites in the region;
- 'vast forest of camping' is a metaphor for the database of campsites and their reviews;
- 'considering only those campsites that have received at least five reviews' ensures that the ratings are based on a sufficient number of reviews to be reliable.

- Popularity is determined by the total number of bookings for each campsite;
- Quality is assessed by the average rating from user reviews;
- A campsite with more bookings and higher ratings is considered more popular and of higher quality.
